def compute(df, window=10):
  import numpy as np
  import pandas as pd
  v = pd.Series(df["volume"])
  def _curv(x):
    if len(x) < window or np.isnan(x).any():
      return np.nan
    a, b, c = np.polyfit(np.arange(window), x.values, 2)
    return 2 * a
  out = v.rolling(window, min_periods=window).apply(_curv, raw=False)
  return out.fillna(0)

