def compute(df, window=10):
  import numpy as np
  import pandas as pd
  v = pd.Series(df["volume"]); idx = np.arange(window)
  def _slope(x):
    if len(x) < window or np.isnan(x).any():
      return np.nan
    n = float(window); sum_x = idx.sum(); sum_y = x.sum(); sum_xy = (idx * x.values).sum(); sum_x2 = (idx * idx).sum(); denom = n * sum_x2 - sum_x * sum_x
    if denom == 0: return np.nan
    return (n * sum_xy - sum_x * sum_y) / denom
  out = v.rolling(window, min_periods=window).apply(_slope, raw=False)
  return out.fillna(0)

